    if ([self.delegate respondsToSelector:@selector(passwordBroadcastSegmentedControl:didSelectItemAtIndex:)]) {
        [self.delegate passwordBroadcastSegmentedControl:self didSelectItemAtIndex:self.selectedIndex];
    }
