@implementation WhiteNoisePlayView

- (instancetype)init {
    self = [super init];
    if (self) {
        [self setUpUI];
        [self setUpEvents];

        if (!self.mode) {
            self.mode = @"A_white.mp3";
        }
        self.targetSeconds = 45;
    }
